return items
  .map(item => {
    const demandDate = new Date(item.json.FKDAT);
    const paymentDate = new Date(item.json.PAY_DATE);

    const diffDays = (paymentDate - demandDate) / (1000 * 60 * 60 * 24);

    if (diffDays >= 0 && diffDays <= 5) {

      const customerId = item.json.KUNNR;
      const rule = "Paid within 5 days";
      const paymentDateStr = item.json.PAY_DATE;
      const today_delta_additions = item.json.today_delta_additions;

      const reference_id = `${customerId}_6000_${paymentDateStr}`;

      return {
        json: {
          customer_id: customerId,
          mobile_number: item.json.MOBILE || null,

          demand_date: item.json.FKDAT,
          payment_date: paymentDateStr,
          diff_days: diffDays,

          points: 6000,
          rule: rule,
          today_delta_additions:today_delta_additions,

          transaction_type: "CREDIT",

          reference_id: reference_id,

          workflow_name: "wallet_incentive_workflow",
          execution_id: $execution.id,

          request_payload: {
            customer_code: customerId,
            demand_date: item.json.FKDAT,
            payment_date: paymentDateStr,
            diff_days: diffDays,
            amount: 6000,
            remarks: rule,
            transaction_note: "Credit points for payment done within 5 days of the demand",
            payment_mode: "cash",
            topup_by: "automation",
            today_delta_additions: today_delta_additions,
          }
        }
      };
    }

    return null;
  })
  .filter(Boolean);

