return items
  .map(item => {

    // Process only Fully Paid records
    if (item.json.paid_status !== "Fully Paid") {
      return null;
    }

    const demandDate =
      new Date(item.json.FKDAT);

    const paymentDate =
      new Date(item.json.PAY_DATE);

    // Invalid date check
    if (
      isNaN(demandDate.getTime()) ||
      isNaN(paymentDate.getTime())
    ) {
      return null;
    }

    const diffDays = Math.floor(
      (paymentDate - demandDate) /
      (1000 * 60 * 60 * 24)
    );

    // Rule: payment within 6–10 days
    if (diffDays > 5 && diffDays <= 10) {

      return {
        json: {

          customer_code:
            item.json.KUNNR,

          demand_date:
            item.json.FKDAT,

          payment_date:
            item.json.PAY_DATE,

          today_delta_additions:
            item.json.today_delta_additions,

          diff_days:
            diffDays,

          amount: 3000,

          remarks:
            "Paid within 10 days",

          transaction_note:
            "Credit points for payment done within 10 days of demand",

          payment_mode:
            "cash",

          topup_by:
            "automation"
        }
      };
    }

    return null;

  })

  .filter(Boolean);

